#!/usr/bin/env python3
"""
Network Configuration Checker

This script detects the operating system and retrieves network interface configuration.
Supports Windows, Linux, and macOS.
"""

import platform
import subprocess
import sys
import json
from typing import Dict, List, Optional

def get_os_type() -> str:
    """Determine the current operating system."""
    system = platform.system().lower()
    if 'windows' in system:
        return 'windows'
    elif 'linux' in system or 'darwin' in system:
        return 'unix'
    else:
        return 'unknown'

def run_command(command: List[str]) -> Optional[str]:
    """Execute a shell command and return its output."""
    try:
        result = subprocess.run(
            command,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            check=True
        )
        return result.stdout.strip()
    except subprocess.CalledProcessError as e:
        print(f"Command failed: {' '.join(command)}", file=sys.stderr)
        print(f"Error: {e.stderr}", file=sys.stderr)
        return None

def parse_ipconfig_output(output: str) -> List[Dict[str, str]]:
    """Parse ipconfig /all output into structured data."""
    interfaces = []
    lines = output.splitlines()
    current_interface = {}

    for line in lines:
        line = line.strip()
        if not line:
            continue

        # Detect interface name (starts with uppercase and ends with colon)
        if ':' in line and any(c.isupper() for c in line):
            if current_interface:
                interfaces.append(current_interface)
            current_interface = {'name': line.split(':')[0].strip()}
        elif 'IPv4 Address' in line:
            addr = line.split(':')[-1].strip()
            current_interface['ipv4'] = addr
        elif 'Subnet Mask' in line:
            mask = line.split(':')[-1].strip()
            current_interface['subnet_mask'] = mask
        elif 'Default Gateway' in line:
            gw = line.split(':')[-1].strip()
            current_interface['gateway'] = gw
        elif 'DNS Servers' in line:
            dns = line.split(':')[-1].strip()
            current_interface['dns_servers'] = dns.split(', ')

    if current_interface:
        interfaces.append(current_interface)
    return interfaces

def parse_unix_output(output: str, tool: str) -> List[Dict[str, str]]:
    """Parse ifconfig or ip addr show output."""
    interfaces = []
    lines = output.splitlines()
    current_interface = None

    for line in lines:
        line = line.strip()
        if not line:
            continue

        # Interface name detection
        if line and not line.startswith(' ') and not line.startswith('inet'):
            parts = line.split()
            if len(parts) >= 1:
                current_interface = {
                    'name': parts[0],
                    'ipv4': '',
                    'subnet_mask': '',
                    'gateway': '',
                    'dns_servers': []
                }
        elif current_interface and line.startswith('inet '):
            # Parse IPv4 address and subnet mask
            parts = line.split()
            if len(parts) >= 2:
                addr_part = parts[1]
                if '/' in addr_part:
                    current_interface['ipv4'] = addr_part.split('/')[0]
                    current_interface['subnet_mask'] = addr_part.split('/')[1]
        elif current_interface and line.startswith('inet6 '):
            # Handle IPv6 if needed
            pass  # Could be extended for IPv6 support

    if current_interface:
        interfaces.append(current_interface)
    return interfaces

def get_network_info() -> Dict[str, any]:
    """Main function to retrieve network configuration."""
    os_type = get_os_type()
    result = {
        'os': os_type,
        'interfaces': [],
        'timestamp': __import__('datetime').datetime.now().isoformat()
    }

    if os_type == 'windows':
        output = run_command(['ipconfig', '/all'])
        if output:
            result['interfaces'] = parse_ipconfig_output(output)
    elif os_type == 'unix':
        # Try 'ip' command first (modern systems), fallback to 'ifconfig'
        output = run_command(['ip', 'addr', 'show'])
        if not output:
            output = run_command(['ifconfig'])
            tool = 'ifconfig'
        else:
            tool = 'ip'

        if output:
            result['interfaces'] = parse_unix_output(output, tool)
    else:
        print(f"Unsupported OS: {os_type}", file=sys.stderr)

    return result

def main():
    """Entry point for script execution."""
    config = get_network_info()
    print(json.dumps(config, indent=2))

if __name__ == '__main__':
    main()

#!/usr/bin/env python3
"""
Network Configuration Retrieval Script
Determines OS and retrieves IP configuration accordingly.
Supports Windows (ipconfig), Linux, and macOS (ifconfig/ip).
"""

import platform
import subprocess
import re

def get_os_type():
    """Determine the operating system."""
    system = platform.system().lower()
    if system == 'windows':
        return 'windows'
    elif system in ['linux', 'darwin']:
        return 'unix'
    else:
        raise OSError(f"Unsupported OS: {system}")

def parse_ipconfig_output(output):
    """Parse ipconfig /all output to extract network details."""
    interfaces = []
    current_interface = None

    for line in output.splitlines():
        line = line.strip()
        if not line:
            continue

        # Detect interface name
        if 'adapter' in line.lower() and ':' in line:
            current_interface = line.split(':')[0].strip()
            interfaces.append({'name': current_interface, 'details': {}})
        elif current_interface and interfaces:
            detail_line = line.lower()
            if 'ipv4 address' in detail_line:
                match = re.search(r'(\d+\.\d+\.\d+\.\d+)', line)
                if match:
                    interfaces[-1]['details']['ipv4'] = match.group(1)
            elif 'subnet mask' in detail_line:
                match = re.search(r'(\d+\.\d+\.\d+\.\d+)', line)
                if match:
                    interfaces[-1]['details']['subnet'] = match.group(1)
            elif 'default gateway' in detail_line:
                match = re.search(r'(\d+\.\d+\.\d+\.\d+)', line)
                if match:
                    interfaces[-1]['details']['gateway'] = match.group(1)
            elif 'dns servers' in detail_line:
                # Simple capture; could be improved for multiple DNS entries
                match = re.search(r'(?:nameserver|server)\s+([\d\.]+)', line)
                if match:
                    interfaces[-1]['details']['dns'] = match.group(1)
    return interfaces

def parse_ifconfig_or_ip_output(output):
    """Parse ifconfig or ip addr show output for Linux/macOS."""
    interfaces = []
    current_interface = None

    for line in output.splitlines():
        line = line.strip()
        if not line:
            continue

        # Match interface name (e.g., 'eth0:', 'lo:', 'en0')
        interface_match = re.match(r'^(\w+)(?::|\s)', line)
        if interface_match:
            current_interface = interface_match.group(1)
            interfaces.append({'name': current_interface, 'details': {}})
        elif current_interface and interfaces:
            # IPv4 Address
            ipv4_match = re.search(r'inet\s+(?:addr:)?(\d+\.\d+\.\d+\.\d+)', line)
            if ipv4_match:
                interfaces[-1]['details']['ipv4'] = ipv4_match.group(1)
            # Subnet Mask (Linux 'ip addr' format)
            subnet_match = re.search(r'inet6?.*?/(?:prefixlen\s+(\d+)|mask\s+(\d+\.\d+\.\d+\.\d+))', line)
            if subnet_match:
                if subnet_match.group(2):  # mask style
                    interfaces[-1]['details']['subnet'] = subnet_match.group(2)
                elif subnet_match.group(1):  # prefix length style
                    # Convert CIDR to subnet mask (basic example)
                    cidr = int(subnet_match.group(1))
                    mask = '.'.join([str((0xffffffff << (32 - cidr) >> i) & 0xff) for i in [24, 16, 8, 0]])
                    interfaces[-1]['details']['subnet'] = mask
            # Gateway (not directly in ifconfig; usually from route command)
            # We'll skip gateway here as it requires additional parsing
    return interfaces

def get_network_interfaces():
    """Main function to retrieve network configuration based on OS."""
    os_type = get_os_type()
    config = {'os': os_type, 'interfaces': []}

    try:
        if os_type == 'windows':
            result = subprocess.run(['ipconfig', '/all'], capture_output=True, text=True, check=True)
            config['interfaces'] = parse_ipconfig_output(result.stdout)
        else:  # unix (linux/mac)
            # Try 'ip' first, fallback to 'ifconfig'
            try:
                result = subprocess.run(['ip', 'addr', 'show'], capture_output=True, text=True, check=True)
                config['interfaces'] = parse_ifconfig_or_ip_output(result.stdout)
            except (subprocess.CalledProcessError, FileNotFoundError):
                result = subprocess.run(['ifconfig'], capture_output=True, text=True, check=True)
                config['interfaces'] = parse_ifconfig_or_ip_output(result.stdout)

    except subprocess.CalledProcessError as e:
        print(f"Command failed: {e}")
    except FileNotFoundError as e:
        print(f"Required command not found: {e}")

    return config

if __name__ == '__main__':
    config = get_network_interfaces()
    import json
    print(json.dumps(config, indent=2))

